import React, { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { Input, Select, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { useVoucherInitData } from '../../../hooks/useVoucherInitData';
import { sxService } from '../../../services/sx/sxService';
import { DocumentFormHeader } from '../../../components/layout';
import { ContractSearchField } from '../../../components/search/ContractSearchField';
import df from '../../../styles/documentForm.module.css';

const emptyForm = {
  orderDate: new Date().toISOString().slice(0, 10),
  contractCode: '',
  productCode: '',
  unitCode: '',
  orderQty: 1,
  plannedStartDate: '',
  plannedEndDate: '',
  description: '',
};

const LsxFormPage: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const isEdit = Boolean(id);
  const isNew = !isEdit;
  const navigate = useNavigate();
  const dispatch = useAppDispatch();

  const initFormName = isEdit ? 'edit-production-order' : 'create-production-order';
  const { unitOptions } = useVoucherInitData(initFormName);
  const unitOpts = [{ value: '', label: '— ĐVT —' }, ...unitOptions];

  const [form, setForm] = useState(emptyForm);
  const [contractCustomerName, setContractCustomerName] = useState('');
  const [code, setCode] = useState('');
  const [loading, setLoading] = useState(isEdit);
  const [saving, setSaving] = useState(false);

  const set = (key: keyof typeof emptyForm, value: string | number) =>
    setForm(prev => ({ ...prev, [key]: value }));

  React.useEffect(() => {
    if (!id) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      sxService
        .getProductionOrder(id)
        .then(o => {
          if (!cancelled) {
            setCode(o.code);
            setForm({
              orderDate: o.orderDate.slice(0, 10),
              contractCode: o.contractCode ?? '',
              productCode: o.productCode,
              unitCode: o.unitCode,
              orderQty: o.orderQty,
              plannedStartDate: o.plannedStartDate?.slice(0, 10) ?? '',
              plannedEndDate: o.plannedEndDate?.slice(0, 10) ?? '',
              description: o.description ?? '',
            });
          }
        })
        .catch(err => {
          if (!cancelled)
            dispatch(addToast({ message: err?.message ?? 'Không tải được LSX', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, dispatch]);

  const handleSave = async () => {
    if (!form.productCode.trim()) {
      dispatch(addToast({ message: 'Vui lòng nhập mã sản phẩm', type: 'error' }));
      return;
    }
    if (!form.orderQty || form.orderQty <= 0) {
      dispatch(addToast({ message: 'Số lượng phải lớn hơn 0', type: 'error' }));
      return;
    }
    setSaving(true);
    try {
      const payload = {
        orderDate: form.orderDate,
        contractCode: form.contractCode || undefined,
        productCode: form.productCode.trim(),
        unitCode: form.unitCode.trim() || 'CAI',
        orderQty: Number(form.orderQty),
        plannedStartDate: form.plannedStartDate || undefined,
        plannedEndDate: form.plannedEndDate || undefined,
        description: form.description || undefined,
      };
      if (isEdit && id) {
        await sxService.updateProductionOrder(id, {
          contractCode: payload.contractCode,
          orderQty: payload.orderQty,
          plannedStartDate: payload.plannedStartDate,
          plannedEndDate: payload.plannedEndDate,
          description: payload.description,
        });
        dispatch(addToast({ message: 'Cập nhật lệnh SX thành công', type: 'success' }));
      } else {
        await sxService.createProductionOrder(payload);
        dispatch(addToast({ message: 'Tạo lệnh SX thành công', type: 'success' }));
      }
      navigate('/sx/lsx');
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className={df.loading}>Đang tải...</div>;

  return (
    <div className={df.page}>
      <DocumentFormHeader
        onBack={() => navigate('/sx/lsx')}
        title={isEdit ? `Sửa lệnh SX ${code}` : 'Tạo lệnh sản xuất'}
        isNew={isNew}
        saving={saving}
        saveLabel="Tạo lệnh SX"
        saveEditLabel="Lưu thay đổi"
        onSave={handleSave}
      />
      <div className={df.section}>
        <h2 className={df.sectionTitle}>Thông tin lệnh</h2>
        <div className={df.row4}>
          <div className={df.field}><label className={df.label}>Ngày lệnh *</label><Input type="date" value={form.orderDate} onChange={e => set('orderDate', e.target.value)} /></div>
          <div className={df.field}><label className={df.label}>Số tham chiếu (HĐ)</label>
            <ContractSearchField
              contractCode={form.contractCode}
              customerName={contractCustomerName}
              onSelect={(code, name) => { set('contractCode', code); setContractCustomerName(name); }}
              onClear={() => { set('contractCode', ''); setContractCustomerName(''); }}
            />
          </div>
          <div className={df.field}><label className={df.label}>Mã sản phẩm *</label><Input value={form.productCode} onChange={e => set('productCode', e.target.value)} disabled={isEdit} /></div>
          <div className={df.field}><label className={df.label}>ĐVT</label>
            <Select value={form.unitCode} onChange={e => set('unitCode', e.target.value)} options={unitOpts} disabled={isEdit} />
          </div>
        </div>
        <div className={df.row4}>
          <div className={df.field}><label className={df.label}>Số lượng *</label><Input type="number" min={1} value={String(form.orderQty)} onChange={e => set('orderQty', Number(e.target.value))} /></div>
          <div className={df.field}><label className={df.label}>Ngày bắt đầu KH</label><Input type="date" value={form.plannedStartDate} onChange={e => set('plannedStartDate', e.target.value)} /></div>
          <div className={df.field}><label className={df.label}>Ngày kết thúc KH</label><Input type="date" value={form.plannedEndDate} onChange={e => set('plannedEndDate', e.target.value)} /></div>
          <div className={df.field}><label className={df.label}>Ghi chú</label><Input value={form.description} onChange={e => set('description', e.target.value)} /></div>
        </div>
      </div>
    </div>
  );
};

export default LsxFormPage;
